using UnityEngine;

/// <summary>
/// Define um "Rumor" (Sistema de Pistas/Rumores) — informação mais indirecta do
/// que uma missão: não inicia nada, apenas fica registada na secção "Rumores"
/// do Diário (DiarySectionUI) depois de ouvida (Action_AddRumor).
///
/// Pode ser uma frase ("text"), uma imagem ("image"), ou ambos — ambos usam o
/// mesmo sistema de exibição em ecrã inteiro (FullscreenImageUI) que as Pistas
/// de missão, mas ficam guardados numa secção separada e NUNCA desaparecem do
/// Diário.
///
/// Quando o jogador descobre a que o rumor se referia (configurável via
/// Action_MarkRumorFound, normalmente dentro de um Action_ConditionalBranch ou
/// evento de NPC/objecto), aparece um ícone de "Check" junto ao rumor na lista
/// — ver PlayerProgress.foundRumorIds / Condition_RumorFound.
/// </summary>
[CreateAssetMenu(menuName = "Animals/Rumor Data", fileName = "NewRumor")]
public class RumorData : ScriptableObject
{
    [Tooltip("Identificador único deste rumor (Action_AddRumor/Action_MarkRumorFound/Condition_HeardRumor/Condition_RumorFound e persistência no save).")]
    public string rumorId;

    [Tooltip("Título curto mostrado na lista de Rumores do Diário (opcional — se vazio, usa o início de 'text').")]
    public string title;

    [TextArea]
    [Tooltip("Frase/texto do rumor (opcional se houver imagem).")]
    public string text;

    [Tooltip("Imagem do rumor, mostrada em ecrã inteiro (FullscreenImageUI) — opcional se houver texto.")]
    public Sprite image;

    [Tooltip("Mundo/região associada a este rumor (apenas para agrupar no Diário, tal como MissionData.suggestedWorld — memória narrativa, não um marcador no mapa).")]
    public WorldData region;
}
